// src/pages/InterviewPage.js
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';
import Webcam from 'react-webcam';
import api from '../services/api';
import { FiCamera, FiCameraOff, FiAlertTriangle, FiClock } from 'react-icons/fi';

const VIOLATION_MAX = 3;

function ViolationWarning({ count, max }) {
  if (count === 0) return null;
  return (
    <motion.div
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0 }}
      className="fixed top-20 left-1/2 -translate-x-1/2 z-50 bg-red-900 border border-red-500 text-red-100 px-6 py-3 rounded-xl flex items-center gap-3 shadow-xl"
    >
      <FiAlertTriangle className="text-red-400" />
      <span className="font-medium">Warning {count}/{max}: {count === 1 ? 'Suspicious activity detected!' : count === 2 ? 'Last warning before auto-submit!' : 'Auto-submitting...'}</span>
    </motion.div>
  );
}

export default function InterviewPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const webcamRef = useRef(null);

  // State
  const [round, setRound] = useState('technical'); // technical | hr | done
  const [questions, setQuestions] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState({});
  const [timeLeft, setTimeLeft] = useState(20);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [violationCount, setViolationCount] = useState(0);
  const [showWarning, setShowWarning] = useState(false);
  const [cameraOn, setCameraOn] = useState(true);
  const [roundStarted, setRoundStarted] = useState(false);
  const timerRef = useRef(null);
  const answerStartRef = useRef(Date.now());

  // Load questions for current round
  const loadQuestions = useCallback(async (roundType) => {
    setLoading(true);
    try {
      const res = await api.get(`/interview/${id}/questions/${roundType}`);
      setQuestions(res.data.questions);
      setCurrentIdx(0);
      setAnswers({});
      setTimeLeft(20);
      setRoundStarted(true);
    } catch (err) {
      toast.error('Failed to load questions');
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    loadQuestions('technical');
    enterFullscreen();
    setupAntiCheat();
    return () => {
      cleanupAntiCheat();
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  // Timer per question
  useEffect(() => {
    if (!roundStarted || loading || questions.length === 0) return;
    answerStartRef.current = Date.now();
    setTimeLeft(20);

    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current);
          handleAutoAdvance();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [currentIdx, roundStarted, questions.length]);

  const handleAutoAdvance = () => {
    const q = questions[currentIdx];
    if (q && !answers[q.id]) {
      setAnswers(prev => ({ ...prev, [q.id]: { selected: 'skipped', timeTaken: 20 } }));
    }
    advanceQuestion();
  };

  const advanceQuestion = () => {
    if (currentIdx < questions.length - 1) {
      setCurrentIdx(prev => prev + 1);
    } else {
      submitRound();
    }
  };

  const selectAnswer = (questionId, option) => {
    if (answers[questionId]) return; // Already answered
    const timeTaken = Math.round((Date.now() - answerStartRef.current) / 1000);
    setAnswers(prev => ({ ...prev, [questionId]: { selected: option, timeTaken } }));
    clearInterval(timerRef.current);
    // Auto-advance after brief delay
    setTimeout(advanceQuestion, 400);
  };

  const submitRound = async () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setSubmitting(true);

    const answerPayload = questions.map(q => ({
      question_id: q.id,
      selected_answer: answers[q.id]?.selected || 'skipped',
      time_taken_seconds: answers[q.id]?.timeTaken || 20,
    }));

    try {
      await api.post(`/interview/${id}/submit-round`, {
        answers: answerPayload,
        round_type: round,
      });

      if (round === 'technical') {
        toast.success('Technical round complete! Starting HR round...');
        setRound('hr');
        setRoundStarted(false);
        await loadQuestions('hr');
      } else {
        // Complete interview
        await api.post(`/interview/${id}/complete`);
        exitFullscreen();
        toast.success('Interview completed! Generating your report...');
        navigate(`/results/${id}`);
      }
    } catch (err) {
      toast.error('Submission failed');
    } finally {
      setSubmitting(false);
    }
  };

  // ── Anti-Cheat ─────────────────────────────────────────────

  const logViolation = useCallback(async (type, description) => {
    try {
      const res = await api.post(`/interview/${id}/violation`, { violation_type: type, description });
      const count = res.data.violation_count;
      setViolationCount(count);
      setShowWarning(true);
      setTimeout(() => setShowWarning(false), 3000);
      if (res.data.auto_submitted) {
        toast.error('Interview auto-submitted due to violations!');
        exitFullscreen();
        navigate(`/results/${id}`);
      }
    } catch { }
  }, [id, navigate]);

  const setupAntiCheat = () => {
    // Block right-click
    document.addEventListener('contextmenu', handleRightClick);
    // Block copy/paste
    document.addEventListener('copy', handleCopy);
    document.addEventListener('paste', handlePaste);
    // Block key shortcuts
    document.addEventListener('keydown', handleKeyDown);
    // Tab visibility
    document.addEventListener('visibilitychange', handleVisibility);
  };

  const cleanupAntiCheat = () => {
    document.removeEventListener('contextmenu', handleRightClick);
    document.removeEventListener('copy', handleCopy);
    document.removeEventListener('paste', handlePaste);
    document.removeEventListener('keydown', handleKeyDown);
    document.removeEventListener('visibilitychange', handleVisibility);
  };

  const handleRightClick = (e) => {
    e.preventDefault();
    logViolation('right_click', 'Right click attempted');
  };

  const handleCopy = (e) => {
    e.preventDefault();
    logViolation('copy_attempt', 'Copy attempted');
  };

  const handlePaste = (e) => {
    e.preventDefault();
    logViolation('paste_attempt', 'Paste attempted');
  };

  const handleKeyDown = (e) => {
    // Block F12, Ctrl+Shift+I, Ctrl+U, etc.
    if (
      e.key === 'F12' ||
      (e.ctrlKey && e.shiftKey && ['I', 'J', 'C'].includes(e.key)) ||
      (e.ctrlKey && e.key === 'u') ||
      (e.ctrlKey && e.key === 'a') ||
      e.key === 'PrintScreen'
    ) {
      e.preventDefault();
      logViolation('keyboard_shortcut', `Blocked shortcut: ${e.key}`);
    }
  };

  const handleVisibility = () => {
    if (document.hidden) {
      logViolation('tab_switch', 'User switched tab or minimized window');
    }
  };

  const enterFullscreen = () => {
    document.documentElement.requestFullscreen?.().catch(() => { });
  };

  const exitFullscreen = () => {
    if (document.fullscreenElement) document.exitFullscreen?.();
  };

  // ── Render ─────────────────────────────────────────────────

  const currentQuestion = questions[currentIdx];
  const progress = questions.length > 0 ? ((currentIdx) / questions.length) * 100 : 0;
  const timerPct = (timeLeft / 20) * 100;
  const timerColor = timeLeft > 10 ? '#6366f1' : timeLeft > 5 ? '#f59e0b' : '#ef4444';

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center gap-4">
        <div className="w-10 h-10 border-2 border-primary-500 border-t-transparent rounded-full animate-spin" />
        <p className="text-slate-400">Preparing your interview...</p>
      </div>
    );
  }

  return (
    <div
      className="min-h-screen bg-slate-950 text-white select-none"
      onContextMenu={e => e.preventDefault()}
    >
      <AnimatePresence>{showWarning && <ViolationWarning count={violationCount} max={VIOLATION_MAX} />}</AnimatePresence>

      {/* Top Bar */}
      <div className="fixed top-0 left-0 right-0 z-40 bg-slate-900/90 backdrop-blur-xl border-b border-slate-800 px-4 py-3">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <div>
            <span className={`text-xs font-semibold px-3 py-1 rounded-full ${round === 'technical' ? 'bg-primary-600/20 text-primary-300' : 'bg-emerald-600/20 text-emerald-300'}`}>
              {round === 'technical' ? '⚡ Technical Round' : '💼 HR Round'}
            </span>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-sm text-slate-400">Q {currentIdx + 1} / {questions.length}</span>

            {/* Timer */}
            <div className="flex items-center gap-2">
              <div className="relative w-9 h-9">
                <svg className="w-9 h-9 -rotate-90" viewBox="0 0 36 36">
                  <circle cx="18" cy="18" r="15" fill="none" stroke="#1e293b" strokeWidth="3" />
                  <circle cx="18" cy="18" r="15" fill="none" stroke={timerColor} strokeWidth="3"
                    strokeDasharray={`${timerPct} 100`} strokeLinecap="round"
                    style={{ transition: 'stroke-dasharray 1s linear, stroke 0.5s' }}
                  />
                </svg>
                <span className="absolute inset-0 flex items-center justify-center text-xs font-bold" style={{ color: timerColor }}>
                  {timeLeft}
                </span>
              </div>
            </div>

            {/* Webcam */}
            <div className={`relative w-12 h-12 rounded-lg overflow-hidden border ${cameraOn ? 'border-emerald-600' : 'border-red-600'}`}>
              {cameraOn ? (
                <Webcam
                  ref={webcamRef}
                  audio={false}
                  width={48}
                  height={48}
                  className="object-cover w-full h-full"
                  onUserMediaError={() => {
                    setCameraOn(false);
                    logViolation('camera_off', 'Camera access denied or turned off');
                  }}
                />
              ) : (
                <div className="w-full h-full bg-slate-800 flex items-center justify-center">
                  <FiCameraOff className="text-red-400 text-xs" />
                </div>
              )}
            </div>

            {violationCount > 0 && (
              <span className="text-xs text-red-400 font-medium">{violationCount} violation{violationCount > 1 ? 's' : ''}</span>
            )}
          </div>
        </div>

        {/* Progress bar */}
        <div className="max-w-5xl mx-auto mt-2">
          <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
            <motion.div
              className="h-full bg-gradient-to-r from-primary-600 to-primary-400 rounded-full"
              style={{ width: `${progress}%` }}
              transition={{ duration: 0.3 }}
            />
          </div>
        </div>
      </div>

      {/* Question */}
      <div className="max-w-3xl mx-auto px-4 pt-28 pb-16">
        <AnimatePresence mode="wait">
          {currentQuestion && (
            <motion.div
              key={currentQuestion.id}
              initial={{ opacity: 0, x: 40 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -40 }}
              transition={{ duration: 0.25 }}
            >
              {/* Skill tag */}
              {currentQuestion.skill_tag && (
                <span className="text-xs text-primary-400 bg-primary-600/10 px-2 py-0.5 rounded-full border border-primary-600/20">
                  {currentQuestion.skill_tag}
                </span>
              )}

              <h2 className="text-xl font-semibold text-white mt-4 mb-8 leading-relaxed">
                {currentIdx + 1}. {currentQuestion.question_text}
              </h2>

              <div className="space-y-3">
                {['A', 'B', 'C', 'D'].map(opt => {
                  const optKey = `option_${opt.toLowerCase()}`;
                  const selected = answers[currentQuestion.id]?.selected;
                  const isSelected = selected === opt;
                  const isAnswered = !!selected;

                  return (
                    <motion.button
                      key={opt}
                      whileHover={!isAnswered ? { scale: 1.01 } : {}}
                      whileTap={!isAnswered ? { scale: 0.99 } : {}}
                      onClick={() => !isAnswered && selectAnswer(currentQuestion.id, opt)}
                      disabled={isAnswered}
                      className={`w-full text-left px-5 py-4 rounded-xl border transition-all duration-200 flex items-center gap-3 ${
                        isSelected
                          ? 'border-primary-500 bg-primary-600/20 text-white'
                          : isAnswered
                          ? 'border-slate-800 bg-slate-900/30 text-slate-500 cursor-not-allowed'
                          : 'border-slate-700 bg-slate-900 text-white hover:border-primary-600/50 hover:bg-slate-800 cursor-pointer'
                      }`}
                    >
                      <span className={`w-7 h-7 rounded-lg flex items-center justify-center text-xs font-bold flex-shrink-0 ${
                        isSelected ? 'bg-primary-600 text-white' : 'bg-slate-800 text-slate-400'
                      }`}>{opt}</span>
                      <span className="text-sm">{currentQuestion[optKey]}</span>
                    </motion.button>
                  );
                })}
              </div>

              {/* Skip */}
              {!answers[currentQuestion.id] && (
                <button
                  onClick={() => {
                    setAnswers(prev => ({ ...prev, [currentQuestion.id]: { selected: 'skipped', timeTaken: 20 - timeLeft } }));
                    clearInterval(timerRef.current);
                    setTimeout(advanceQuestion, 100);
                  }}
                  className="mt-6 text-slate-500 hover:text-slate-300 text-sm transition-colors"
                >
                  Skip question →
                </button>
              )}
            </motion.div>
          )}
        </AnimatePresence>

        {/* Submit manually */}
        {currentIdx === questions.length - 1 && answers[currentQuestion?.id] && (
          <motion.button
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            onClick={submitRound}
            disabled={submitting}
            className="mt-8 w-full bg-gradient-to-r from-emerald-600 to-emerald-700 hover:from-emerald-500 disabled:opacity-50 text-white font-semibold py-4 rounded-xl transition-all flex items-center justify-center gap-2"
          >
            {submitting
              ? <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />Submitting...</>
              : round === 'technical' ? '✅ Submit Technical Round' : '🎉 Submit HR Round & Finish'
            }
          </motion.button>
        )}
      </div>
    </div>
  );
}
